import { css } from '@emotion/react';

import { colors } from '@/styles/colors.ts';

type NotesPaginationProps = {
  currentPage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
};

export default function NotesPagination({
  currentPage,
  totalPages,
  onPageChange,
}: NotesPaginationProps) {
  if (totalPages <= 1) return null;

  const isFirst = currentPage === 1;
  const isLast = currentPage === totalPages;
  const isEndFirst = currentPage > 3;
  const isEndLast = currentPage <= totalPages - 3;

  return (
    <nav css={navCss}>
      {isEndFirst && (
        <button type="button" onClick={() => onPageChange(1)}>
          {String.fromCharCode(171)}
        </button>
      )}

      {!isFirst && (
        <button type="button" onClick={() => onPageChange(currentPage - 1)}>
          {'‹'}
        </button>
      )}

      {Array.from(
        { length: totalPages },
        (_, i) =>
          i > currentPage - 4 &&
          i < currentPage + 2 && (
            <button
              key={i + 1}
              type="button"
              className={i + 1 === currentPage ? 'active' : ''}
              onClick={() => onPageChange(i + 1)}
            >
              {i + 1}
            </button>
          ),
      )}

      {!isLast && (
        <button type="button" onClick={() => onPageChange(currentPage + 1)}>
          {'›'}
        </button>
      )}

      {isEndLast && (
        <button type="button" onClick={() => onPageChange(totalPages)}>
          {String.fromCharCode(187)}
        </button>
      )}
    </nav>
  );
}

const navCss = css`
  display: flex;
  justify-content: center;
  gap: 6px;
  margin-top: 40px;
  margin-bottom: 32px;

  button {
    display: flex;
    align-items: center;
    justify-content: center;
    min-width: 36px;
    height: 36px;
    padding: 0 4px;
    border-radius: 8px;
    font-size: 1.4rem;
    color: ${colors.midgrey};
    background: var(--tag-background);
    border: 1px solid var(--nav-border-color);
    cursor: pointer;
    transition: all 0.2s ease;

    &.active {
      color: var(--main-color);
      font-weight: 600;
      background: var(--background-color);
      border-color: var(--main-color);
      cursor: default;
    }

    &:hover:not(.active) {
      color: var(--main-color);
      border-color: ${colors.midgrey};
    }
  }

  @media (max-width: 500px) {
    gap: 4px;

    button {
      min-width: 32px;
      height: 32px;
      font-size: 1.3rem;
    }
  }
`;
