import { useCallback, useEffect, useState } from 'react';

const REPO_OWNER = 'pozafly';
const REPO_NAME = 'pozafly.github.io';
const PER_PAGE = 20;

export type GitHubLabel = {
  id: number;
  name: string;
  color: string;
};

export type GitHubIssue = {
  id: number;
  number: number;
  title: string;
  body: string;
  body_html: string;
  labels: GitHubLabel[];
  created_at: string;
  updated_at: string;
  html_url: string;
  reactions: {
    '+1': number;
    '-1': number;
    laugh: number;
    hooray: number;
    confused: number;
    heart: number;
    rocket: number;
    eyes: number;
    total_count: number;
  };
  comments: number;
};

type UseGitHubIssuesReturn = {
  issues: GitHubIssue[];
  loading: boolean;
  error: string | null;
  currentPage: number;
  totalPages: number;
  goToPage: (page: number) => void;
  activeLabel: string | null;
  setActiveLabel: (label: string | null) => void;
  labels: GitHubLabel[];
};

async function fetchTotalCount(label: string | null): Promise<number> {
  const parts = [`repo:${REPO_OWNER}/${REPO_NAME}`, 'state:open', 'is:issue'];
  if (label) {
    parts.push(`label:"${label}"`);
  }

  const params = new URLSearchParams({ q: parts.join(' '), per_page: '1' });
  const response = await fetch(`https://api.github.com/search/issues?${params}`, {
    headers: { Accept: 'application/vnd.github.v3+json' },
  });

  if (!response.ok) return 0;

  const data: { total_count: number } = await response.json();
  return data.total_count;
}

export function useGitHubIssues(): UseGitHubIssuesReturn {
  const [issues, setIssues] = useState<GitHubIssue[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [activeLabel, setActiveLabel] = useState<string | null>(null);
  const [labels, setLabels] = useState<GitHubLabel[]>([]);

  const fetchIssues = useCallback(async (pageNum: number, label: string | null) => {
    setLoading(true);
    setError(null);

    try {
      const params = new URLSearchParams({
        state: 'open',
        per_page: String(PER_PAGE),
        page: String(pageNum),
        sort: 'created',
        direction: 'desc',
      });
      if (label) {
        params.set('labels', label);
      }

      const [response, totalCount] = await Promise.all([
        fetch(`https://api.github.com/repos/${REPO_OWNER}/${REPO_NAME}/issues?${params}`, {
          headers: { Accept: 'application/vnd.github.full+json' },
        }),
        fetchTotalCount(label),
      ]);

      if (!response.ok) {
        throw new Error(
          response.status === 403
            ? 'GitHub API 요청 한도를 초과했습니다. 잠시 후 다시 시도해주세요.'
            : '노트를 불러오는데 실패했습니다.',
        );
      }

      setTotalPages(Math.max(1, Math.ceil(totalCount / PER_PAGE)));

      const data: GitHubIssue[] = await response.json();
      const filtered = data.filter(
        (issue) => !(issue as unknown as { pull_request: unknown }).pull_request,
      );

      setIssues(filtered);
    } catch (err) {
      setError(err instanceof Error ? err.message : '알 수 없는 에러가 발생했습니다.');
    } finally {
      setLoading(false);
    }
  }, []);

  // 라벨 목록 가져오기
  useEffect(() => {
    async function fetchLabels() {
      try {
        const response = await fetch(
          `https://api.github.com/repos/${REPO_OWNER}/${REPO_NAME}/labels`,
          {
            headers: { Accept: 'application/vnd.github.v3+json' },
          },
        );
        if (response.ok) {
          const data: GitHubLabel[] = await response.json();
          setLabels(data);
        }
      } catch {
        // 라벨 로딩 실패는 무시
      }
    }
    fetchLabels();
  }, []);

  // 라벨 변경 시 리셋
  useEffect(() => {
    setCurrentPage(1);
    fetchIssues(1, activeLabel);
  }, [activeLabel, fetchIssues]);

  const goToPage = useCallback(
    (page: number) => {
      setCurrentPage(page);
      fetchIssues(page, activeLabel);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    },
    [activeLabel, fetchIssues],
  );

  return {
    issues,
    loading,
    error,
    currentPage,
    totalPages,
    goToPage,
    activeLabel,
    setActiveLabel,
    labels,
  };
}
